(5, 28, 'Website Design & Development', '1712335364.jpg', 'Apollo Infotech is leading Wesite design and development service provider. there are three different type of website\r\nStatic website\r\ndynamic website\r\nE-commerce website.', NULL, 12000, 65000, NULL, 1, 0, '42.106.33.70', 88, 88, '2024-04-05 15:32:15', '2024-04-05 16:42:44', 'ranged', NULL),
(6, 28, 'Static Website', '1712335556.jpg', 'A static website is a simple & cost-effective way to showcase your business online. It is built using HTML, CSS, and Javascript and does not require any server side scripting or database management.\r\n\r\nWith a static website, you can ensure fast load times, strong security, and easy maintenance, making it ideal for small businesses, personal portfolios, and informational sites.', NULL, 8000, 18000, NULL, 1, 0, '42.106.33.70', 88, NULL, '2024-04-05 16:45:56', NULL, 'ranged', NULL),
(7, 28, 'Mobile App Developement', '1712336688.jpg', 'Are you looking to develop a cutting-edge mobile app that meets the needs of your target audience? Apollo Infotech is a leading mobile app development company based in Ahmedabad that provides comprehensive and customized app development services to clients across various industries. With a team of experienced and skilled app developers, we strive to deliver high- quality and user-friendly mobile applications that meet the unique needs of our clients.', NULL, 15000, 85000, NULL, 1, 0, '42.106.33.70', 88, NULL, '2024-04-05 17:04:48', NULL, 'ranged', NULL),
(8, 28, 'E-commerce WEb & App Development', '1712336892.jpg', 'At Apollo Infotech, design matters when it comes to your e-commerce website. We create websites that are visually appealing and easy to navigate, helping you attract more potential customers and increase conversions. Our team of experienced web developers uses the latest technology to create e-commerce websites that gives full online shopping experience to increase your revenue through increased sales, traffic, client retention, and ROI .', NULL, 40000, 140000, NULL, 1, 0, '42.106.33.70', 88, NULL, '2024-04-05 17:08:12', NULL, 'ranged', NULL),
(9, 28, 'SEO', '1712337047.jpg', 'At Apollo Infotech, we understand that having a strong online presence is crucial to the success of any business. That’s why we offer comprehensive SEO services that include website audits, keyword research, on-page optimization, off-page optimization, link building and content creation.', NULL, 10000, 35000, NULL, 1, 0, '42.106.33.70', 88, NULL, '2024-04-05 17:10:47', NULL, 'ranged', NULL),
