(116, 100, 'Milky teeth/ pediatric treatment', '1722090870.jpg', 'Milky teeth or baby tooth stay in kids oral cavity for few years only but their importance requires immediate attention in every small problem. They may require any dental procedure which we do in adults as well. It requires lots of patience and care. Routine dental visit habit should be started as early as possible for kids.', NULL, NULL, NULL, NULL, 1, 0, '49.14.135.29', 160, NULL, '2024-07-27 14:34:30', NULL, NULL, 'Milkyteeth, pediatricteeth, temporaryteeth, kidsdentist, kidsteeth, milkyteethtreatment, babybottlecavities, milkyteethrct, spacemaintainer, habitbreakingappliance, thumbsucking, lipbiting, tonguethursting, nailbiting, teethclenching, kidstoothremoval'),
(117, 100, 'Full mouth rehabilitation', '1722092132.jpg', 'FMR is the ultimate saviour for the patient with severe dental problems. It uses the natural anchorage of tooth with bone and replaces the crown part of tooth. It gives immense satisfaction to patient who restrict their smile because of appearance or darkness of teeth. It gives you freedom to eat like natural teeth and significantly improves the smile and face.', NULL, NULL, NULL, NULL, 1, 0, '49.14.135.29', 160, NULL, '2024-07-27 14:55:32', NULL, NULL, 'FMR, fullmouthrehab, fullmouthteethreplacement, fixeddentition, metalceramicteeth, emaxcrown, zirconia, allceramicteeth, 3dscannedteeth'),
(118, 71, 'corporate meals', '', 'we provide everyday meals', 350, NULL, NULL, NULL, 1, 0, '106.200.212.195', 131, NULL, '2024-08-01 13:14:46', NULL, 'fixed', 'meals'),
(119, 101, 'Jewellry', '', '<p data-mce-style=\"text-align: justify;\" style=\"color: rgb(0, 0, 0); font-family: PlayfairDisplay-Regular, sans-serif; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; width: 370px; caret-color: rgb(0, 0, 0); -webkit-text-size-adjust: 100%; text-align: justify;\">Since 1999, MK Jewels has been a benchmark for design, craftsmanship, quality, and price. As India’s leading manufacturer and retailer of real diamond, gold, and CZ jewelry, we offer more than 5000 exclusive designs and a wide-ranging collection. Over the past 20 years, we have successfully established a factory and stores in Mumbai and Ahmedabad alongside a loyal customer base across the country and globally.</p><p data-mce-style=\"text-align: justify;\" style=\"color: rgb(0, 0, 0); font-family: PlayfairDisplay-Regular, sans-serif; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; width: 370px; caret-color: rgb(0, 0, 0); -webkit-text-size-adjust: 100%; text-align: justify;\">With an in-house manufacturing atelier and an exceptional design team, each piece of jewelry is designed with great detail and is a true mark of excellence. We blend the unmatched beauty of handmade in India with state-of-the-art technology to ensure our jewelry is as unique as you. We are up-to-date with industry trends and encourage buyer feedback to present our patrons with the finest jewelry in the world. We offer our customers a transparent and seamless shopping experience with a Made-To-Order service, Lifelong Exchange Policy, and Certified Jewellery.</p><p data-mce-style=\"text-align: justify;\" style=\"color: rgb(0, 0, 0); font-family: PlayfairDisplay-Regular, sans-serif; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; width: 370px; caret-color: rgb(0, 0, 0); -webkit-text-size-adjust: 100%; text-align: justify;\"><br></p><p data-mce-style=\"text-align: justify;\" style=\"color: rgb(0, 0, 0); font-family: PlayfairDisplay-Regular, sans-serif; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; width: 370px; caret-color: rgb(0, 0, 0); -webkit-text-size-adjust: 100%; text-align: justify;\">Whether you are looking for everyday wear, occasion wear, or gifting, MK JEWELS is your one-stop jewelry shopping destination for the best in quality, design, and price!&nbsp;</p>', NULL, 10000, 2000000, NULL, 1, 0, '106.205.230.218', 161, NULL, '2024-08-01 13:58:45', NULL, 'ranged', 'Gifts, investment, gold, diamond, lab grown diamonds, polki, jadau, temple jewelry, rings, bangles, bracelets, necklace, pendant, pendant sets, earrings, ginni, gold biscuit, bullion, gifting,'),
