(139, 33, 'We deal in all type of sports gears and equipment', '1723562382.jpeg', '<div>We deal in cricket gears, football ,volleyball, tennis, table tennis, badminton , skates, swimming costumers , swimming caps , swimming goggles, sportswear, track pant, active wear t-shirts, sports accessories, retail and institutional sales of sports goods and clothing, customized team t-shirts, Sports even management.</div><div><br></div>', NULL, NULL, NULL, NULL, 1, 0, '117.99.103.242', 93, NULL, '2024-08-13 15:19:42', NULL, NULL, 'cricket gears, football ,volleyball, tennis, table tennis, badminton , skates, swimming costumers , swimming caps , swimming goggles, sportswear, track pant, active wear t-shirts, sports accessories, retail and institutional sales of sports goods and clothing, customized team t-shirts, Sports even management.'),
(140, 72, 'Colorful Chorus Scarfs', '1724336633.jpg', '<h3><b><font face=\"comic sans ms\" size=\"5\">✨ Colorful Chorus Scarf ✨</font></b></h3><div><font face=\"comic sans ms\"><br></font></div><div><font size=\"4\" face=\"comic sans ms\">Elevate your wardrobe with our collection of scarves, perfect for any season and occasion. From the bold patterns that speak of daring adventures to the subtle hues that whisper of classic sophistication, there’s a piece for every tale. So go ahead, let your scarf be the narrator of your fashion journey.</font></div><div><font size=\"4\" face=\"comic sans ms\"><br></font></div><div><font face=\"comic sans ms\" size=\"4\"><b>MEASUREMENTS:</b> Length: 78\" - 198 cms&nbsp; &nbsp; Width: 22\" - 56 cms</font></div><div><font face=\"comic sans ms\" size=\"4\"><br></font></div><div><font face=\"comic sans ms\" size=\"4\"><b>FABRICS:</b> <font color=\"#009900\" style=\"\">Cotton Silk:</font> High end, Luxurious, Delicate, super soft texture, extremely light weight and flows beautifully. Crafted with the finest fabrics, our scarves offer both durability and a soft touch. Print on one side, the other side is slightly lighter.</font></div><div><font face=\"comic sans ms\" size=\"4\"><br></font></div><div><font face=\"comic sans ms\" size=\"4\"><b>STYLING / PRINT:</b> Beautiful bright shades of colour. Whether you’re dressing up or keeping it casual, our scarves add a touch of sophistication to any outfit. Drape, wrap, or tie your scarf in countless ways to express your unique style. <i><font color=\"#3366cc\">Please note that our scarves are Fashion scarves, they are not meant to keep you warm.</font>&nbsp;</i></font></div><div><font face=\"comic sans ms\" size=\"4\"><br></font></div><div><font face=\"comic sans ms\" size=\"4\"><b>FINISH:</b> Neat edges. Hemmed on all four sides.&nbsp;</font></div><div><font face=\"comic sans ms\" size=\"4\"><br></font></div><div><font face=\"comic sans ms\" size=\"4\"><b>CARE INSTRUCTIONS:</b> We recommend a gentle hand wash or dry clean to preserve the delicate arƟstry. Treat them with love, and they’ll keep you wrapped in beauty for years to come.</font></div><div><ul><li><font face=\"comic sans ms\" size=\"4\">Gentle cold hand wash separately</font></li><li><font face=\"comic sans ms\" size=\"4\">Do not bleach</font></li><li><font face=\"comic sans ms\" size=\"4\">Iron cool</font></li><li><font face=\"comic sans ms\" size=\"4\">Do not tumble dry. Dry in shade</font></li><li><font face=\"comic sans ms\" size=\"4\">Do not rub</font></li><li><font face=\"comic sans ms\" size=\"4\">Dry Clean</font></li></ul></div><div><font face=\"comic sans ms\" size=\"4\"><i>The gentler you are, longer it will look great.</i></font></div><div><font face=\"comic sans ms\" size=\"4\"><br></font></div><div><font face=\"comic sans ms\" size=\"4\"><b>CUSTOM ORDERS:</b> We use high quality pure material such as <i>tussar silk/ silk/ crape/ georgette/ chiffon/ cotton or any other cloth</i> of your preference.</font></div><div><br></div><div><br></div><div><font face=\"comic sans ms\" size=\"3\"><b>Perfect as a gift- </b>We can ship directly to the recipient, and we will not send an invoice with the package.</font></div><div><font face=\"comic sans ms\" size=\"3\">Product colour may slightly vary due to photographic lighting sources or your monitor settings.</font></div><div><font face=\"comic sans ms\" size=\"3\">All Items are shipped from Ahmedabad, India.</font></div><div><font face=\"comic sans ms\" size=\"3\"><br></font></div><div><font face=\"comic sans ms\" size=\"3\"><i>We are more than happy to help with any queries to ensure that you are completely satisfied with your purchase!</i></font></div>', 1999, NULL, NULL, NULL, 1, 0, '111.93.93.243', 132, NULL, '2024-08-22 14:23:53', NULL, 'fixed', '#Scarfs #scarves #art #wedding #party #luxury #fashion #occasion #cotton #creative #design #art #style #weddingphotography #business #color #traditional #handpainted #customized #decor #handcrafted'),
(141, 113, 'Basic Health check up', '1726040802.png', '<blockquote style=\"margin: 0 0 0 40px; border: none; padding: 0px;\">Basic health check up plan includes<b> tests</b> that require for <b>screening</b> of all body organs.<div>&nbsp;We have designed this package in such a way that covers almost all basic tests for <b>age group 25- 40 years.</b></div><div>Those who falls into such age group need to go through this screening package&nbsp; atleast<b> once a year.</b></div><h6><span style=\"font-weight: normal;\">We will consult you afterwards about the results and what needs to do further.</span></h6><h6><span style=\"background-color: var(--vz-card-bg); color: var(--vz-card-color); font-family: var(--vz-body-font-family); font-size: var(--vz-body-font-size); font-weight: var(--vz-body-font-weight); text-align: var(--vz-body-text-align);\">Stay healthy , Stay fit.&nbsp;</span></h6></blockquote>', 750, NULL, NULL, NULL, 1, 0, '43.250.157.112', 174, 174, '2024-09-11 07:46:42', '2024-09-21 13:45:57', 'fixed', 'Basic health check up plan , body profile , screening profile , blood test , laboratory, test'),
(142, 113, 'Body Profile Male', '1726041633.png', 'Body profile Male is designed specially for males of age group 40 - 55 years.<div>Those who falls into this age group needs tests like LIPID Profile , Thyroid Profile -TSH , T3 , T4&nbsp; and PSA very frequently to be done&nbsp;</div><div>to diagnose early changes in these hormones level .</div><div>That will help to prevent so many future complications by early diagnosing it.</div><div>If you know someone falls in this category then u should definitely suggest them this profile.</div><div>Stay Healthy Stay fit.</div>', 1600, NULL, NULL, NULL, 1, 0, '43.250.157.112', 174, 174, '2024-09-11 08:00:33', '2024-09-21 13:33:51', 'fixed', 'body profile male , male health check up plan , annual check up male, blood test , laboratory, test.'),
(143, 113, 'Body Profile Female', '1726042238.png', 'Body profile Female designed for<b> 25-45 years of Females</b>.<div>In these years of female life we face so many hormonal ups and down , &amp; with hectic schedule</div><div>we often forgot to take care of ourselves .</div><div>Thats why we came up with Female Health check up plan that covers<b> THYROID Hormone , IRON , FERRITINE , SUGAR , CALCIUM and</b></div><div><b>many more tests.</b></div><div><b>By going through these screening tests we can come up with so many untold problems\' solution.</b></div><div><b>Stay Healthy , Stay fit&nbsp;</b></div>', 1600, NULL, NULL, NULL, 1, 0, '43.250.157.112', 174, 174, '2024-09-11 08:10:38', '2024-09-21 13:33:30', 'fixed', 'Female body check up plan, Female health check up , Women\'s Health check up plan , Women\'s screening package , blood test , laboratory , test .'),
(144, 113, 'Pre marital screening profile', '1726047841.jpg', 'Yes you seen it right.&nbsp;<div>It is pre marital screening package.</div><div>Why it is important ??</div><div>Who can get the benifits of it ?</div><div>This package is specially for those <b>couples</b> who are getting married soon.</div><div>This includes tests like <b>hepatitis B</b> , <b>hepatitis C </b>, <b>HIV</b> , <b>syphilis</b> , <b>Thalassemia</b> screening test etc.</div><div>Some disease can be prevented just by taking some precautions and that why this package is must for all the newly engaged couples.</div><div>Don\'t miss this one if you want happy marriage.</div><div>Stay healthy , stay fit.</div>', 1700, NULL, NULL, NULL, 1, 0, '106.77.95.109', 174, NULL, '2024-09-11 09:44:01', NULL, 'fixed', 'Pre marital screening package , pre marital health check up , before marriage health check up plan'),
(145, 113, 'Executive body check up', '1726048519.png', 'This package includes almost all the tests.<div>Full body check up includes&nbsp;</div><div><b>Liver function tests</b> , <b>kidney function tests</b> , <b>thyroid function tests</b> , <b>fasting sugar</b> , <b>hba1c</b> , <b>vitamin B12</b> , <b>vitamin D3</b> , Prostate specific antigen <b>PSA</b> for male&nbsp; &amp; <b>CA 125</b> for female.</div><div>Preferred Age group <b>40- 65 years.</b></div><div>This is a detailed health check up plan.</div><div>Stay Healthy , stay Fit</div>', 3400, NULL, NULL, NULL, 1, 0, '43.250.157.112', 174, 174, '2024-09-11 09:55:19', '2024-09-21 13:33:06', 'fixed', 'Executive body check up plan , premium package , full body check up , detailed health screening package , blood test , laboratory , test'),
(146, 113, 'Pre employment health check up', '1726049169.png', 'We are also doing pre employment health check up which includes blood tests , x ray , PFT , and many more tests.<div>It can be customised according to your requirement.</div><div>Feel free to connect with us for your company and employees.</div><div><br></div>', NULL, 200, 1000, NULL, 1, 0, '103.240.204.158', 174, NULL, '2024-09-11 10:06:09', NULL, 'ranged', 'Pre employment health check up , employment health screening , employees annual health checkup'),
(147, 113, 'Industrial health check up', '1726049497.png', 'Industrial health check up includes blood tests , urine examination , xray , sonography , pulmonary function tests , physician consultant.<div>It can be customised according to your needs .</div><div>Feel free to connect with us and to know more.</div><div><br></div>', NULL, 250, 1000, NULL, 1, 0, '103.240.204.158', 174, NULL, '2024-09-11 10:11:37', NULL, 'ranged', 'Industrial health check up , industrial health plan , employees health check up'),
(148, 98, 'Falling for the Light | Book by Shaymi Shah', '1727256572.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Introduce a pause in the everyday chaos with this beautifully illustrated book of narratives, from battling anxiety and loneliness to finding connection and healing.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">‘Falling for the Light’ by Shaymi Shah takes you on a journey of seeking answers, even in the darkness, and finding them through nuanced instances by observing the world around us carefully. Every page compels you to slow down into the present moment and take a chance to reflect on your experiences.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">This book is a collection of imagined possibilities through timeless conversations with elements in nature. It allows you to escape from the reality momentarily and step into a world of imagination and wonder. It is a gentle reminder to find what fuels&nbsp;your&nbsp;soul.&nbsp;</p>', 399, NULL, NULL, NULL, 1, 0, '122.170.169.17', 158, NULL, '2024-09-25 09:29:32', NULL, 'fixed', '#author #book #selfhelp #journeywithin #booklover #selfdiscovery'),
(149, 98, 'Priority Planner', '1727256885.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">We are all dreamers and love to make our dreams come true. Procrastination, however, is the greatest challenge we encounter on our journey. Even after using numerous websites and tools to stay on top of our job, we still manage to get distracted!&nbsp;</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">This priority planner, inspired from the Eisenhower matrix, has been designed to help you divide your tasks into four separate grids: urgent and important, urgent and not important, urgent and important, and urgent and not important. The biggest advantage of using this planner would be to schedule your day into manageable tasks.</p>', 180, NULL, NULL, NULL, 1, 0, '122.170.169.17', 158, NULL, '2024-09-25 09:34:45', NULL, 'fixed', '#priorityplanner #deskessentials #johariwindow #eisenhowermatrix'),
(150, 98, 'Scented Shot glass candles- box of 4', '1727462079.JPG', '<span style=\"color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; font-size: 16px; background-color: rgb(245, 247, 249);\">Inhale this pleasant aroma that is sure to put you in a cheerful mood. The labels on the shot glass candles themselves spread good vibes and zen. Our ‘Scented Shot Glass Candles’ are known not only for aromatherapy but also for some self-motivation. Their scented candles come with motivational quotes and a lovely scent—a perfect recipe for some relaxation. Choose any 4 out of our 15 fragrance options to curate your own gift box.&nbsp;</span><br>', 700, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 18:34:39', NULL, 'fixed', '#candles #aromatherapy #candlelovers #calmingscents #scentedcandles #gifthampers #diwaligifting #festivegifting'),
(152, 98, 'Test tube planter', '1727462852.JPG', '<span style=\"color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; font-size: 16px; background-color: rgb(245, 247, 249);\">Bring a blend of science and style to your living space with SOEL’s exclusive Test Tube Planter. Crafted with a sleek glass tube and a ceramic stand, this unique planter exudes modernity and elegance, effortlessly complementing any interior design theme. Whether propagating new plant life, showcasing air plants, or nurturing a single stem, this planter provides endless possibilities for displaying your favourite greenery stylishly and unconventionally. Available in three shapes- Hexagonal, Square and oval and four colours- pink, purple, blue, green&nbsp;</span><br>', 550, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 18:47:32', NULL, 'fixed', '#planter #naturelovers #testubeplanter #propogrationcentre #homedeocor #gifting'),
(153, 98, 'U-cone candles', '1727462954.JPG', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Candles have been scientifically proven to relax us. Their soothing, entrancing glow makes them an ideal addition to any relaxing practice. SOEL, on the other hand, takes the science of candles a step further by developing a u-cone scented candle that is shown to change your mood.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Our scented u-cone scented candle has fragrances that make you feel good, as well as aromas that remind us of pleasant or happy memories.&nbsp;Available in 4 fragrances.&nbsp;</p>', 500, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 18:49:14', NULL, 'fixed', '#candles #aromatherapy #moodenhancing #wellness #gifting #homedecor'),
(154, 98, 'Premium Wooden diary | Personalized', '1727463104.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.75em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Take your writing to the next level with our handcrafted, personalized wooden diary with SOEL. This A5 journal has a durable wooden cover with a beautiful design and 96 pages of ruled SSP 100 Natural Shade Paper, which makes for a pleasant writing surface. You get to pick between two stunning designs to have engraved on the hardwood cover:</p><ol style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 3em; outline: 0px; padding: 0px; vertical-align: baseline; list-style-position: initial; list-style-image: initial; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\"><li style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-style: inherit; font-weight: inherit; margin: 0px; outline: 0px; padding: 0px; vertical-align: baseline;\">To Create Magic, One Must Keep the Spark Alive</li><li style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-style: inherit; font-weight: inherit; margin: 0px; outline: 0px; padding: 0px; vertical-align: baseline;\">Yin Yang</li></ol>', 1500, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 18:51:44', NULL, 'fixed', '#personalizedgifting #corporategifting #premiumgifting'),
(155, 98, 'Hybrid journals', '1727463677.JPG', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">‘Hybrid Journals’ have a combination of blank, lined and dotted pages. They feature Shaymi Shah’s inspirational quotes along with beautiful digital illustrations on the cover as well in the inner pages.<span style=\"font-weight: var(--vz-body-font-weight); text-align: var(--vz-body-text-align);\">&nbsp;The choice of different page layouts supports flexible writing, so you may easily capture your thoughts, goals, and dreams.</span></p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">The text printed on the cover of these journals is digitally foiled for a stunning finish with perfect binding. Despite the hectic pace of modern life, these journals encourage you to savour each passing moment by writing in them. Available in 6 cover options.&nbsp;</p>', 500, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 19:01:17', NULL, 'fixed', '#journaling #growthmindset #writing #diaries #stationery'),
(156, 98, 'Floral Bookmarks', '1727463828.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Keep beautifully preserved pressed flower art wherever you go with a handmade bookmark from SOEL. Each pressed flower bookmark has a print of one of our distinctive pressed flower patterns paired with a quote to amuse, celebrate, or inspire.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\"><span style=\"box-sizing: inherit; --bdt-inverse: initial;\">This aesthetically pleasing bookmark is sure to give an essence of meadow to your eyes.&nbsp;</span>Bright colored flowers make it look more vibrant along with the quote.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Each flower bookmark has been carefully laminated to ensure long-lasting durability. The handmade floral bookmarks are ideal for birthdays, anniversaries, weddings, Mother’s Day, and other special occasions. We have several designs of pressed flower bookmarks to select from. You can get 1 piece or a set of 3 pieces.&nbsp;</p>', NULL, 120, 300, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 19:03:48', NULL, 'ranged', '#bookmarks #booklovers #pressedflowerart #flowerpressed'),
(157, 98, 'Premium wiro diary', '1727464295.heic', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Unleash your inner writer and embrace endless possibilities with our Premium Wiro Diaries designed to elevate your journaling experience and become a cherished companion on your path to self-discovery.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Powerful message on the covers serve as a daily reminder to greet each new day with fresh starts, renewed purpose, and unwavering optimism.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">The A5 size offers ample space to capture your thoughts, dreams, and aspirations in clear, flowing strokes. We want to ensure a comfortable writing experience, no matter where inspiration strikes. Available in 6 different cover and colour options. It can be personalized with your brand logo and name on MOQ basis.&nbsp;</p>', 400, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, 158, '2024-09-27 19:07:42', '2024-09-27 19:11:35', 'fixed', '#wirodiaries #stationery #corporategifting #diwaligifting'),
(158, 98, 'Brown Kraft paper journal', '1727464152.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">The best partner for both work and personal life! SOEL’s Brown Kraft Paper Journal is ideal for anyone who enjoys taking notes on nearly everything. The cover features a digital illustration along with the poem that will motivate you to work towards your well-being, goals, and much more.&nbsp;</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Note, scribble, write. Do whatever you like. Our journal contains printed lined pages that allow you to record related topics without restriction, making your recording more personal.</p>', 260, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 19:09:12', NULL, 'fixed', '#kraftpaperjournal #journaling #kraftpaper #sustainablestationery'),
(159, 98, 'Concrete Coasters- Box of 4', '1727464442.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Brace yourself for an explosion of creativity as we present to you our edge coasters with four mind-blowing design categories: element graphic, quote, pattern, and image!</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Our four different design categories—element graphic, quote, pattern, or image—can help you get ideas from the way the sun and moon move in time with each other.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">Because each coaster is made by hand, no two are exactly the same. They are a celebration of individuality. Bring the natural beauty of the world into your home to help you stay in the present. In “Edge Coasters,” you can see how nature and human workmanship work together perfectly.</p>', 850, NULL, NULL, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 19:14:02', NULL, 'fixed', '#concretecoasters #homedecor #giftingideas #diwaligfiting #bulkgifting'),
(160, 98, 'Resin concrete coasters- (box of 2/4/6)', '1727464603.jpg', '<p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">The “Resin Concrete Coaster” is an example of how form and function can harmoniously coexist. This meticulously made coaster exemplifies the perfect synthesis of form and function. The personal bond between art and workmanship is on full display in every item, which evokes strong feelings.</p><p style=\"box-sizing: inherit; --bdt-inverse: initial; border: 0px; font-size: 16px; margin-right: 0px; margin-bottom: 1.6em; margin-left: 0px; outline: 0px; padding: 0px; vertical-align: baseline; color: rgb(0, 0, 0); font-family: Helvetica, Verdana, Arial, sans-serif; background-color: rgb(245, 247, 249);\">These coasters are more than just decorative accents; they’re statements about your personality and taste, along with an artfully selected quotation. With their eye-catching graphics, each coaster is like a mini-work of art that will liven up your room.</p>', NULL, 750, 1800, NULL, 1, 0, '49.36.10.28', 158, NULL, '2024-09-27 19:16:43', NULL, 'ranged', '#resinconcrete #homedecor #giftingideas #diwaligfiting #bulkgifting #festivegifting');
