(1, 1, 'women day celebration', '1771935034.png', 'amcaklcaca<div>adasdasdasd</div><div>asdasdasdasd</div>', '2026-03-11', '2026-03-11', 'No', NULL, 'Yes', 50, 1, 0, '103.1.100.226', 1, NULL, '2026-02-24 12:10:34', '0000-00-00 00:00:00', 'women-day-celebration');
INSERT INTO `Overteem` (`Overteem_id`, `Overteem_name`, `Overteem_photo`, `description`, `designation`, `isteam`, `strIP`, `iStatus`, `isDelete`, `created_at`, `updated_at`) VALUES
(1, 'Ms. Ruchi Shah', '1768983069.png', 'GrOath is the outcome of five years of continuous observation and evolution in business by its founder, Ruchi Shah.\r\n\r\nThrough mentoring entrepreneurs across multiple cities in India and leading thriving business communities, she uncovered a fundamental truth: real business doesn’t happen in noisy rooms or crowded platforms. It happens in quiet, focused, and trusted environments, where leaders have the time to engage in meaningful conversations beyond introductions.\r\n\r\nGrOath was created to serve entrepreneurs—regardless of scale—who value a vetted circle, need time to articulate their business, and prefer networking that aligns with their professional rhythm.\r\n\r\nAt GrOath, members don’t need a microphone.\r\nThey need the mindset to grow.', 'FOUNDER & DIRECTOR', 1, '122.167.146.227', 1, 0, NULL, NULL),
(2, 'Adv. Prachi Shonu', '1711690369.jpeg', 'Her experience as professional lawyer for almost two decades have paved a way to deeply understand the working model of various business segments. Her forte in non-litigation has an invaluable contribution to the GrOath business community.', 'Director', 0, '103.1.100.226', 1, 0, NULL, NULL),
(3, 'Shri Nayan Kunvarji Thakkar', '1717419534.jpeg', 'Shri Nayan Kunvarji Thakkar , is the Managing Director of the Kunvarji Group of Companies and has been instrumental in the formation of the group. With his rich experience of more than 30 years in the financial market, Mr Nayan is guiding the group to the next progressive era. He is an enterprising leader that propels the business forward. At GrOath, his involvement as a main promoter inspires us to progress and bring the best of Business Networking service to our community.', 'Promoter', 0, '182.69.30.199', 1, 0, NULL, NULL),
(4, 'Ms Bhumi Choksi', '1768983992.png', 'Networking goes far beyond transactions—it is about relationships that create long-term value. At GrOath, we believe that a strong network ultimately defines one’s net worth. Meaningful networking is built on genuine connections and strengthened through trust, which—once established—continues to deliver value over a lifetime.\r\n\r\nThis philosophy is deeply rooted in the journey of our founder member, Bhumi Choksi. With over a decade of experience as a baker and entrepreneur, she learned that consistent quality, integrity, and relationship-building are as critical as the product itself. The trust-based relationships formed with customers, partners, and collaborators becomes the foundation of sustained growth and long-term credibility. She continues to apply this same ideology in her role as Chapter Director at GrOath. \r\n\r\nShe says \" by prioritizing trust, collaboration, and shared values, we are building a focused business community where relationships translate into lasting net worth \"', 'FOUNDER MEMBER & CHAPTER DIRECTOR', 1, '122.167.146.227', 1, 0, NULL, NULL),
(5, 'Mr. Hardik Shah', '1768986325.png', 'With over 11 years of experience as a Skill Evaluator Consultant at Brainbow DNE, he has helped individuals discover and unlock their innate potential. His work has consistently focused on guiding people toward aligned decision-making—choices that support their professional direction while strengthening personal and social growth. He brings this depth of experience into his role at GrOath.\r\n\r\nTo him, networking is not about collecting numbers, but about building the right numbers—meaningful connections, visibility, and consistency. He believes the true measure of networking lies not in immediate business outcomes, but in how many people know you, trust your intent, and witness your growth journey over time.\r\n\r\nAs Chapter Director at GrOath Pinnacle and a member of the Think Tank Committee, he places members at the center of every initiative. His leadership ensures opportunities for authentic relationship-building while preserving GrOath’s minimalistic, value-first ideology. Anchored in member growth, consistent engagement, and long-term vision, his approach focuses on creating a strong foundation for sustainable success.', 'CHAPTER DIRECTOR', 1, '122.167.146.227', 1, 0, NULL, NULL),
(6, 'Ms. Rachana Tated', '1768986523.png', 'Eyewear is more than fashion—it is the clinical art of dispensing frames that enhance, correct, and protect vision. Rachana Tated, Co-Founder of Ainakwala, takes pride in building a trusted optical care brand serving over 35,000+ families in Ahmedabad, with expansion underway in Surat.\r\n\r\nJust as spectacles and sunglasses have become everyday necessities, networking has become a core driver of her business expansion and community growth. A member of GrOath since its inception, she has played an active role in shaping its ideology and represents the GrOath Think Tank across various business forums. As GrOath continues to evolve, she remains deeply aligned with its mindset—focused on clarity, purpose, and collective growth.\r\n\r\nShe believes that while time moves swiftly, growth belongs to those who navigate it wisely, stay focused, and lead with intention. For her, GrOath is an ocean of opportunities—a space where every connection is respected, meaningful, and reciprocated, enabling her to grow professionally while contributing to a stronger, growth-first community.', 'FOUNDER MEMBER', 1, '122.167.146.227', 1, 0, NULL, NULL),
(7, 'Ms. RASSHMI CHAJJER', '1768986760.png', 'Fashion, for her, goes beyond design—it is about creating personalised expressions through craftsmanship, fit, and fabric. Rashmi Chhajer, Founder of Label Reshamm, brings over 20 years of experience in customised clothing. With a loyal community of 800+ clients, Reshamm is known for its elegance, comfort, timeless style, perfect fits, fine fabrics, and flawless finishing, catering to men, women, and children across all occasions.\r\n\r\nA Founder Member of GrOath and an active member of the Think Tank, she is closely involved in shaping strategic decisions within the GrOath Network. Her focus remains on ensuring that every member has equal opportunity to grow, while maintaining the organisation’s core values of fairness, quality, and long-term vision.\r\n\r\nIntroduced to GrOath by Ruchi Shah, she connected instantly with its cluster-meet model and minimalistic, purpose-driven approach to networking. Working closely with the core team, she continues to witness and support the founder’s vision as it evolves into a strong, trusted, and growth-focused business community.', 'Founder Member', 1, '122.167.146.227', 1, 0, NULL, NULL);
