(7, 'Hir Sanghvi', '9429744477', 'hirsanghvi21@gmail.com', 'Employee', 'Service', 'Vivek kadecha lifestyle and interior design', 52, 'Pvt Ltd', 'Ahmedabad', 0, '', 'It’s a small scale design firm where we take commercial and residential interior projects and small scale architectural projects and every project has new design methodology.', '2026-02-02 20:08:57', '2026-02-02 20:08:57', 'Mostly rest and personal time', 'People openly share what they’re building', 'I’m learning and preparing for my next move', 'Get new perspectives or ideas', 'To gain exposure and direction', ''),
(8, 'Shivani', '8980880441', 'shivanijain1509@gmail.com', 'Professional', 'Service', 'Fund Space', 44, '', 'Ahmedabad', 1, 'BNI', 'Hello ... I m a Financial Advisor .. \r\nI m into this Field Since last 10 years ... \r\nI manage my Friends and Family portfolio worth Rs 25 Crore ...', '2026-02-04 09:09:00', '2026-02-04 09:09:00', '>A mix of chill and something productive', 'People openly share what they’re building', 'I’m working professionally and open to collaborations', 'Have meaningful conversations, not just cards', 'To collaborate and grow with like-minded people', ''),
